  ingredients: ["Water  -  1 cup", "All-purpose flour  -  1 cup", "Butter  -  2 tbsp", "Sugar  -  1 tbsp", "Salt  -  ¼ tsp", "Egg  -  1 large", "Vanilla extract  -  ½ tsp", "Oil for frying  -  as needed", "Cinnamon sugar (for rolling)  -  ½ cup sugar + 1 tsp cinnamon"],
